#include <iostream>
#include <iomanip>
#include <vector>

using Score = int;
using Average = double;

int main() {
    int n{};
    std::cin >> n;

    std::vector<Score> scores(static_cast<std::size_t>(n));
    for (auto& s : scores)
        std::cin >> s;

    auto sum { 0 };
    for (const auto& s : scores)
        sum += s;

    const Average avg { static_cast<Average>(sum) / n };

    auto aboveCount { 0 };
    for (const auto& s : scores)
        if (s > avg)
            ++aboveCount;

    const Average pct { static_cast<Average>(aboveCount) / n * 100.0 };

    std::cout << std::fixed;
    std::cout << "Sum: " << sum << '\n';
    std::cout << "Average: " << std::setprecision(2) << avg << '\n';
    std::cout << "Above average: " << std::setprecision(1) << pct << "%\n";
}

