#include <iostream>
#include <iomanip>

using Centimetres = double;
using Millimetres = int;

auto toCentimetres(int feet) -> Centimetres {
    return feet * 30.48;
}

auto toMillimetres(Centimetres cm) -> Millimetres {
    return static_cast<Millimetres>(cm * 10.0);
}

int main() {
    int feet{};
    std::cin >> feet;

    const auto cm { toCentimetres(feet) };
    const auto mm { toMillimetres(cm) };

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Feet: " << feet << '\n';
    std::cout << "Centimetres: " << cm << '\n';
    std::cout << "Millimetres: " << mm << '\n';
}
